	/** Hash buckets are replayed directly; the control uses the pre-chunk row chain on the identical join. */
	@State(Scope.Benchmark)
	public static class HashReplayState extends QueryState {

		private static final int ROOTS = 2_048;
		private static final int HOT_BUCKET_MATCHES = 513;
		private static final int HOT_ROOT_REPEATS = 64;
		private static final String[] RESULT_NAMES = { "root", "value" };

		@Param({ "directHashReplay", "rowChain" })
		public String strategy;

		@Setup(Level.Trial)
		public void setUp() {
			boolean directReplay = "directHashReplay".equals(strategy);
			setProperty(PARALLEL_FLAG, "false");
			setProperty(FACTORIZED_ROWS_FLAG, "true");
			setProperty(CHUNK_FLAG, Boolean.toString(directReplay));
			setProperty(CHUNKED_PREFIX_FLAG, "false");
			setProperty(CHUNK_MERGE_FLAG, "false");
			setProperty(CHUNK_SIP_FLAG, "false");
			openRepository();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				ValueFactory vf = connection.getValueFactory();
				IRI rootPredicate = vf.createIRI(EX, "hashRoot");
				IRI lookupPredicate = vf.createIRI(EX, "hashLookup");
				IRI tailPredicate = vf.createIRI(EX, "hashTail");
				connection.begin();
				for (int i = 0; i < ROOTS; i++) {
					IRI root = vf.createIRI(EX, "hash/root/" + i);
					boolean hotRoot = i >= ROOTS - HOT_ROOT_REPEATS;
					IRI key = vf.createIRI(EX, hotRoot ? "hash/key/hot" : "hash/key/" + i);
					IRI value = vf.createIRI(EX, hotRoot ? "hash/value/hot/0" : "hash/value/" + i);
					connection.add(root, rootPredicate, key);
					connection.add(key, lookupPredicate, value);
					connection.add(value, tailPredicate,
							vf.createIRI(EX, hotRoot ? "hash/leaf/hot/0" : "hash/leaf/" + i));
					// The repeated hot key arrives after the scan-once switch. Replaying its immutable 513-row
					// bucket enough times makes the avoided classic-array copy visible to allocation profiling.
					if (i == ROOTS - HOT_ROOT_REPEATS) {
						for (int match = 1; match < HOT_BUCKET_MATCHES; match++) {
							IRI hotValue = vf.createIRI(EX, "hash/value/hot/" + match);
							connection.add(key, lookupPredicate, hotValue);
							connection.add(hotValue, tailPredicate, vf.createIRI(EX, "hash/leaf/hot/" + match));
						}
					}
					// Keep the root predicate uniquely cheapest while retaining a finite lookup sweep estimate.
					connection.add(vf.createIRI(EX, "hash/noise/key/" + i), lookupPredicate,
							vf.createIRI(EX, "hash/noise/value/" + i));
					connection.add(vf.createIRI(EX, "hash/noise/tail-a/" + i), tailPredicate,
							vf.createIRI(EX, "hash/noise/leaf-a/" + i));
					connection.add(vf.createIRI(EX, "hash/noise/tail-b/" + i), tailPredicate,
							vf.createIRI(EX, "hash/noise/leaf-b/" + i));
				}
				connection.commit();
			}
			query = "SELECT ?root ?value WHERE { "
					+ "?root <" + EX + "hashRoot> ?key . "
					+ "?key <" + EX + "hashLookup> ?value . "
					+ "?value <" + EX + "hashTail> ?ignored . }";
			expectedRows = ROOTS - HOT_ROOT_REPEATS + (long) HOT_ROOT_REPEATS * HOT_BUCKET_MATCHES;
			verifyBindingChecksum = true;
			LmdbStore store = (LmdbStore) repository.getSail();
			try (SailDataset dataset = backingStore(store).getExplicitSailSource().dataset(IsolationLevels.NONE)) {
				NativeLmdbQuerySource source = requireNativeDataset(dataset);
				ValueFactory vf = SimpleValueFactory.getInstance();
				expectedBindingChecksum = 0L;
				for (int i = 0; i < ROOTS; i++) {
					long rootId = requiredId(source, vf.createIRI(EX, "hash/root/" + i));
					if (i >= ROOTS - HOT_ROOT_REPEATS) {
						for (int match = 0; match < HOT_BUCKET_MATCHES; match++) {
							long valueId = requiredId(source, vf.createIRI(EX, "hash/value/hot/" + match));
							expectedBindingChecksum += nativeBindingChecksum(rootId, valueId);
						}
					} else {
						long valueId = requiredId(source, vf.createIRI(EX, "hash/value/" + i));
						expectedBindingChecksum += nativeBindingChecksum(rootId, valueId);
					}
				}
			}

			long buildsBefore = LmdbNativeChunkPipeline.HASH_BUILDS.get();
			long chunkBefore = LmdbNativeChunkPipeline.ENGAGED.get();
			long replayRowsBefore = LmdbNativeChunkPipeline.HASH_REPLAY_ROWS.get();
			executeChecked();
			long buildDelta = LmdbNativeChunkPipeline.HASH_BUILDS.get() - buildsBefore;
			long chunkDelta = LmdbNativeChunkPipeline.ENGAGED.get() - chunkBefore;
			long replayRowsDelta = LmdbNativeChunkPipeline.HASH_REPLAY_ROWS.get() - replayRowsBefore;
			if (directReplay && (buildDelta <= 0L || chunkDelta <= 0L
					|| replayRowsDelta < (long) HOT_ROOT_REPEATS * HOT_BUCKET_MATCHES)) {
				throw new IllegalStateException("directHashReplay telemetry: builds=" + buildDelta + ", chunks="
						+ chunkDelta + ", replayRows=" + replayRowsDelta + ", requiredReplayRows="
						+ (long) HOT_ROOT_REPEATS * HOT_BUCKET_MATCHES);
			}
			if (!directReplay && (buildDelta != 0L || chunkDelta != 0L || replayRowsDelta != 0L)) {
				throw new IllegalStateException("rowChain unexpectedly engaged the chunk hash path");
			}
		}

		@Override
		long bindingChecksum(BindingSet row) {
			return nativeBindingChecksum(row, RESULT_NAMES);
		}

		@TearDown(Level.Trial)
		public void tearDown() throws IOException {
			closeRepositoryAndRestoreProperties();
		}
	}

	/**
	 * Slot-owned payload reuse is compared with the generic top-K over the same query and data. That control measures
	 * the whole factorized strategy, not the payload store in isolation; allocation attribution therefore uses JFR and
	 * the same {@code slotOwnedPayload} workload before and after the payload-store implementation change.
	 */
	@State(Scope.Benchmark)
	public static class TopKReplacementState extends QueryState {

		private static final int RANKS = 512;
		private static final int ENUM_ROWS = 513;
		private static final String[] RESULT_NAMES = { "s", "rank", "a", "p", "v", "g" };

		@Param({ "slotOwnedPayload", "genericTopK" })
		public String strategy;
		private long[] expectedBindingIds;

		@Setup(Level.Trial)
		public void setUp() {
			boolean slotOwned = "slotOwnedPayload".equals(strategy);
			setProperty(PARALLEL_FLAG, "false");
			setProperty(FACTORIZED_ROWS_FLAG, "true");
			setProperty(ORDERED_FACTORIZED_FLAG, Boolean.toString(slotOwned));
			openRepository();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				ValueFactory vf = connection.getValueFactory();
				IRI rankPredicate = vf.createIRI(EX, "rank");
				IRI edgePredicate = vf.createIRI(EX, "edge");
				connection.begin();
				for (int i = 0; i < RANKS; i++) {
					connection.add(vf.createIRI(EX, "topk/subject/" + i), rankPredicate, vf.createLiteral(i));
				}
				for (int i = 0; i < ENUM_ROWS; i++) {
					connection.add(vf.createIRI(EX, "topk/enum/" + i), edgePredicate,
							vf.createIRI(EX, "topk/value/" + i), vf.createIRI(EX, "topk/graph/" + i));
				}
				connection.commit();
			}
			query = "SELECT ?s ?rank ?a ?p ?v ?g WHERE { "
					+ "?s <" + EX + "rank> ?rank . GRAPH ?g { ?a ?p ?v } "
					+ "} ORDER BY DESC(?rank) LIMIT 1";
			expectedRows = 1;
			verifyBindingChecksum = true;

			// Capture the complete result term IDs from the ordinary native top-K before timing either mode. This
			// validates every projected binding without materializing lazy RDF values in measured invocations.
			setProperty(ORDERED_FACTORIZED_FLAG, "false");
			try {
				QuerySummary reference = evaluateSummary();
				if (reference.rows != expectedRows || expectedBindingIds == null) {
					throw new IllegalStateException("generic top-K reference returned " + reference.rows + " rows");
				}
				expectedBindingChecksum = reference.bindingChecksum;
			} finally {
				setProperty(ORDERED_FACTORIZED_FLAG, Boolean.toString(slotOwned));
			}

			long topKBefore = NativeRowsStep.ORDERED_FACTORIZED_TOPK.get();
			long replacementsBefore = NativeTopKBuffer.REPLACEMENTS.get();
			executeChecked();
			if (slotOwned && NativeRowsStep.ORDERED_FACTORIZED_TOPK.get() <= topKBefore) {
				throw new IllegalStateException("slotOwnedPayload did not engage ordered factorized top-K");
			}
			if (slotOwned && NativeTopKBuffer.REPLACEMENTS.get() - replacementsBefore != RANKS - 1L) {
				throw new IllegalStateException("slotOwnedPayload did not replace every improving K=1 candidate");
			}
			if (!slotOwned && NativeRowsStep.ORDERED_FACTORIZED_TOPK.get() != topKBefore) {
				throw new IllegalStateException("genericTopK unexpectedly engaged ordered factorization");
			}
		}

		@Override
		void validateRow(BindingSet row) {
			if (expectedBindingIds == null) {
				Value rank = row.getValue("rank");
				if (rank == null || !Integer.toString(RANKS - 1).equals(rank.stringValue())) {
					throw new IllegalStateException("generic top-K reference selected " + rank);
				}
				expectedBindingIds = copyNativeBindingIds(row, RESULT_NAMES);
				return;
			}
			assertNativeBindingIds(row, RESULT_NAMES, expectedBindingIds);
		}

		@Override
		long bindingChecksum(BindingSet row) {
			return nativeBindingChecksum(row, RESULT_NAMES);
		}

		@TearDown(Level.Trial)
		public void tearDown() throws IOException {
			closeRepositoryAndRestoreProperties();
		}
	}

	/** Isolates live-slot payload reuse from the previous append-only arena under identical top-K admissions. */
	@State(Scope.Benchmark)
	public static class IsolatedTopKPayloadState {

		private static final int RANKS = 384;
		private static final int ENUM_MATCHES = 513;
		private static final int ENUM_STRIDE = 4;
		private static final int METADATA_OFFSET = 2;
		private static final int PACKED_WIDTH = METADATA_OFFSET + 2;
		private static final int[] ENUM_VALUE_SLOTS = { 4, 5, 6, 7 };
		private static final PackedRowComparator DESCENDING_RANK = (left, leftOffset, right, rightOffset) -> Long
				.compare(right[rightOffset], left[leftOffset]);

		@Param({ "liveSlots", "appendOnlyArena" })
		public String strategy;

		private final long[] payload = new long[ENUM_MATCHES * ENUM_STRIDE];
		private final PayloadCursor cursor = new PayloadCursor(payload);

		@Setup(Level.Trial)
		public void setUp() {
			for (int i = 0; i < payload.length; i++) {
				payload[i] = i;
			}
			executeChecked();
		}

		long executeChecked() {
			boolean liveSlots = "liveSlots".equals(strategy);
			if (!liveSlots && !"appendOnlyArena".equals(strategy)) {
				throw new IllegalArgumentException(strategy);
			}
			FactorizedTail.MemoBudget budget = new FactorizedTail.MemoBudget(FactorizedTail.MEMO_BYPASSES);
			NativeTopKBuffer best = new NativeTopKBuffer(PACKED_WIDTH, 1, DESCENDING_RANK, budget);
			TopKPayloadStore payloadStore = liveSlots ? new TopKPayloadStore(1, budget) : null;
			LmdbNativeLongArena arena = liveSlots ? null : new LmdbNativeLongArena();
			if (arena != null) {
				arena.attachCapacityBudget(budget);
			}
			long[] packed = new long[PACKED_WIDTH];
			try {
				for (int rank = 0; rank < RANKS; rank++) {
					packed[0] = rank;
					packed[1] = 1L;
					int acceptedSlot = best.tryAdmit(packed, rank, METADATA_OFFSET);
					if (acceptedSlot < 0) {
						throw new IllegalStateException("monotonically improving rank was not admitted: " + rank);
					}
					payload[0] = rank;
					payload[payload.length - 1] = rank + payload.length;
					if (payloadStore != null) {
						if (!payloadStore.store(acceptedSlot, cursor, 1, packed, METADATA_OFFSET)) {
							throw new IllegalStateException("live-slot payload budget refused rank " + rank);
						}
					} else {
						long offset = arena.append(payload, 0, payload.length);
						if (offset == LmdbNativeLongArena.REFUSED) {
							throw new IllegalStateException("append-only payload budget refused rank " + rank);
						}
						packed[METADATA_OFFSET] = offset;
						packed[METADATA_OFFSET + 1] = ENUM_MATCHES;
					}
					best.replaceAcceptedSuffix(acceptedSlot, packed, METADATA_OFFSET);
				}

				long rank = best.buffer.id(0, 0);
				long offset = best.buffer.id(0, METADATA_OFFSET);
				long first = payloadStore != null ? payloadStore.get(0, offset) : arena.get(offset);
				long lastOffset = offset + payload.length - 1L;
				long last = payloadStore != null ? payloadStore.get(0, lastOffset) : arena.get(lastOffset);
				long checksum = 31L * rank + 17L * first + last;
				long expectedRank = RANKS - 1L;
				long expected = 31L * expectedRank + 17L * expectedRank + expectedRank + payload.length;
				if (checksum != expected) {
					throw new IllegalStateException(strategy + " payload checksum " + checksum + " != " + expected);
				}
				return checksum;
			} finally {
				if (payloadStore != null) {
					payloadStore.close();
				}
				if (arena != null) {
					arena.reset();
				}
				best.close();
			}
		}

		private static final class PayloadCursor implements FlatRowCursor {

			private final long[] values;

			private PayloadCursor(long[] values) {
				this.values = values;
			}

			@Override
			public boolean next() {
				return false;
			}

			@Override
			public long multiplicity() {
				return 1L;
			}

			@Override
			public int enumCount() {
				return 1;
			}

			@Override
			public int[] enumValueSlots(int i) {
				if (i != 0) {
					throw new IndexOutOfBoundsException(i);
				}
				return ENUM_VALUE_SLOTS;
			}

			@Override
			public long[] enumValues(int i) {
				if (i != 0) {
					throw new IndexOutOfBoundsException(i);
				}
				return values;
			}

			@Override
			public long enumMatches(int i) {
				if (i != 0) {
					throw new IndexOutOfBoundsException(i);
				}
				return ENUM_MATCHES;
			}

			@Override
			public void close() {
				// Trial-owned immutable cursor view; no resources.
			}
		}
	}

	/** Parallel workers use an external-root chunk stage; the control retains their row-at-a-time probe chain. */
	@State(Scope.Benchmark)
	public static class ExternalRootChunkState extends QueryState {

		private static final int THREADS = 4;
		private static final int REPEAT = 16;
		// Exercise the production eligibility regime rather than forcing a sub-threshold query into parallelism.
		private static final int ROOTS = 65 * LmdbNativeChunkPipeline.BATCH_ROWS + 1;
		private static final String[] RESULT_NAMES = { "subject", "value" };

		@Param({ "externalRootChunk", "workerRowChain" })
		public String strategy;

		@Param({ "uniqueKeys", "repeatedKeys" })
		public String workload;

		@Setup(Level.Trial)
		public void setUp() {
			boolean chunk = "externalRootChunk".equals(strategy);
			setProperty(PARALLEL_FLAG, "true");
			setProperty(PARALLEL_THRESHOLD_FLAG, "50000");
			setProperty(PARALLEL_THREADS_FLAG, Integer.toString(THREADS));
			setProperty(PARALLEL_TASKS_FLAG, "5");
			setProperty(FACTORIZED_ROWS_FLAG, "true");
			setProperty(NATIVE_BATCH_FLAG, "false");
			setProperty(CHUNK_FLAG, Boolean.toString(chunk));
			setProperty(LmdbNativeChunkPipeline.EXTERNAL_ROOT_CANDIDATE_PROPERTY, Boolean.toString(chunk));
			setProperty(CHUNKED_PREFIX_FLAG, "false");
			setProperty(CHUNK_MERGE_FLAG, "true");
			setProperty(CHUNK_SIP_FLAG, "true");
			openRepository();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				ValueFactory vf = connection.getValueFactory();
				IRI rootPredicate = vf.createIRI(EX, "parallelRoot");
				IRI valuePredicate = vf.createIRI(EX, "parallelValue");
				IRI tailPredicate = vf.createIRI(EX, "parallelTail");
				connection.begin();
				for (int i = 0; i < ROOTS; i++) {
					int key = "repeatedKeys".equals(workload) ? i / REPEAT : i;
					IRI subject = vf.createIRI(EX, "parallel/subject/" + i);
					IRI middle = vf.createIRI(EX, "parallel/middle/" + key);
					IRI value = vf.createIRI(EX, "parallel/value/" + i);
					connection.add(subject, rootPredicate, middle);
					connection.add(middle, valuePredicate, value);
					connection.add(value, tailPredicate, vf.createIRI(EX, "parallel/tail/" + i));
				}
				connection.commit();
			}
			query = "SELECT ?subject ?value WHERE { "
					+ "?subject <" + EX + "parallelRoot> ?middle . "
					+ "?middle <" + EX + "parallelValue> ?value . "
					+ "?value <" + EX + "parallelTail> ?ignored . }";
			if ("repeatedKeys".equals(workload)) {
				long completeGroups = ROOTS / REPEAT;
				long remainder = ROOTS % REPEAT;
				expectedRows = completeGroups * REPEAT * REPEAT + remainder * remainder;
			} else {
				expectedRows = ROOTS;
			}
			verifyBindingChecksum = true;

			// Capture a sequential native reference over the same snapshot. The checksum uses projected physical IDs,
			// so measured runs validate every binding without value materialization and parallel output order is
			// irrelevant.
			setProperty(PARALLEL_FLAG, "false");
			try {
				QuerySummary reference = evaluateSummary();
				if (reference.rows != expectedRows) {
					throw new IllegalStateException("external-root reference returned " + reference.rows + " rows");
				}
				expectedBindingChecksum = reference.bindingChecksum;
			} finally {
				setProperty(PARALLEL_FLAG, "true");
			}

			long parallelBefore = LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get();
			long chunkBefore = LmdbNativeChunkPipeline.ENGAGED.get();
			long hashBefore = LmdbNativeChunkPipeline.HASH_BUILDS.get();
			long mergeBefore = LmdbNativeChunkPipeline.MERGE_WALKS.get();
			long sipBefore = LmdbNativeChunkPipeline.SIP_MASKS.get();
			executeChecked();
			if (LmdbNativeParallelPipelines.PARALLEL_ROW_RUNS.get() <= parallelBefore) {
				throw new IllegalStateException(strategy + " did not engage parallel row workers");
			}
			if (chunk && LmdbNativeChunkPipeline.ENGAGED.get() <= chunkBefore) {
				throw new IllegalStateException("externalRootChunk did not engage the chunk pipeline");
			}
			if (!chunk && LmdbNativeChunkPipeline.ENGAGED.get() != chunkBefore) {
				throw new IllegalStateException("workerRowChain unexpectedly engaged the chunk pipeline");
			}
			if (LmdbNativeChunkPipeline.HASH_BUILDS.get() != hashBefore) {
				throw new IllegalStateException(strategy + " unexpectedly built a worker-local hash table");
			}
			if (LmdbNativeChunkPipeline.MERGE_WALKS.get() != mergeBefore
					|| LmdbNativeChunkPipeline.SIP_MASKS.get() != sipBefore) {
				throw new IllegalStateException(strategy + " unexpectedly engaged merge-walk or SIP acceleration");
			}
		}

		@Override
		long bindingChecksum(BindingSet row) {
			return nativeBindingChecksum(row, RESULT_NAMES);
		}

		@TearDown(Level.Trial)
		public void tearDown() throws IOException {
			closeRepositoryAndRestoreProperties();
		}
	}

	/**
	 * Same-build A/B for the composite source's retained child handles. Both modes use the same composite, child
	 * sources, key sequence, rows, and complete drain loop. The control reproduces the interface's legacy default
	 * probe: every open creates a fresh composite statement iterator, which in turn opens each child through
	 * statements().
	 */
	@State(Scope.Benchmark)
	public static class CompositeProbeState extends QueryState {

		private static final int PROBE_KEYS = 768;

		@Param({ "retainedChildren", "legacyPerOpen" })
		public String strategy;
		@Param({ "explicitAndInferred", "explicitOnly" })
		public String sourceShape;

		private NativeLmdbQuerySource source;
		private SailDataset explicitDataset;
		private SailDataset inferredDataset;
		private final long[] probeSubjects = new long[PROBE_KEYS];
		private long predicateId;
		private long expectedChecksum;

		@Setup(Level.Trial)
		public void setUp() throws IOException {
			openRepository();
			ValueFactory vf = SimpleValueFactory.getInstance();
			IRI predicate = vf.createIRI(EX, "compositeProbe");
			IRI[] subjects = new IRI[PROBE_KEYS];
			IRI[] objects = new IRI[PROBE_KEYS];
			LmdbStore store = (LmdbStore) repository.getSail();
			try (LmdbStoreConnection connection = (LmdbStoreConnection) store.getConnection()) {
				connection.begin();
				for (int i = 0; i < PROBE_KEYS; i++) {
					subjects[i] = vf.createIRI(EX, "composite-probe/subject/" + i);
					objects[i] = vf.createIRI(EX, "composite-probe/object/" + i);
					if ("explicitAndInferred".equals(sourceShape) && (i & 1) != 0) {
						connection.addInferredStatement(subjects[i], predicate, objects[i]);
					} else if ("explicitAndInferred".equals(sourceShape) || "explicitOnly".equals(sourceShape)) {
						connection.addStatement(subjects[i], predicate, objects[i]);
					} else {
						throw new IllegalArgumentException(sourceShape);
					}
				}
				connection.commit();
			}

			SailStore backingStore = backingStore(store);
			explicitDataset = backingStore.getExplicitSailSource().dataset(IsolationLevels.NONE);
			inferredDataset = backingStore.getInferredSailSource().dataset(IsolationLevels.NONE);
			source = CompositeNativeLmdbQuerySource.combine(List.of(
					requireNativeDataset(explicitDataset), requireNativeDataset(inferredDataset)));
			if (source == null) {
				throw new IllegalStateException("real explicit and inferred datasets did not form a native composite");
			}
			predicateId = requiredId(source, predicate);
			expectedChecksum = 0L;
			for (int i = 0; i < PROBE_KEYS; i++) {
				long subjectId = requiredId(source, subjects[i]);
				long objectId = requiredId(source, objects[i]);
				probeSubjects[i] = subjectId;
				expectedChecksum += checksum(subjectId, predicateId, objectId,
						LmdbNativeAggregateCompiler.NULL_CONTEXT_ID);
			}
			executeCheckedProbes();
		}

		long executeCheckedProbes() throws IOException {
			NativeProbe probe;
			if ("retainedChildren".equals(strategy)) {
				probe = source.newProbe();
			} else if ("legacyPerOpen".equals(strategy)) {
				probe = legacyPerOpenProbe(source);
			} else {
				throw new IllegalArgumentException(strategy);
			}
			long rows = 0L;
			long actualChecksum = 0L;
			try (probe) {
				for (long subject : probeSubjects) {
					try (RecordIterator iterator = probe.open(subject, predicateId,
							NativeLmdbQuerySource.UNKNOWN_ID, NativeLmdbQuerySource.UNKNOWN_ID)) {
						long[] row;
						while ((row = iterator.next()) != null) {
							rows++;
							actualChecksum += checksum(row[0], row[1], row[2], row[3]);
						}
					}
				}
			}
			if (rows != PROBE_KEYS || actualChecksum != expectedChecksum) {
				throw new IllegalStateException(strategy + ": expected " + PROBE_KEYS + " rows/checksum "
						+ expectedChecksum + " but got " + rows + "/" + actualChecksum);
			}
			return actualChecksum;
		}

		private static long checksum(long subj, long pred, long obj, long context) {
			return 31L * subj + 17L * pred + obj + context;
		}

		private static NativeProbe legacyPerOpenProbe(NativeLmdbQuerySource source) {
			return new NativeProbe() {
				private RecordIterator current;

				@Override
				public RecordIterator open(long subj, long pred, long obj, long context) throws IOException {
					if (current != null) {
						current.close();
					}
					current = source.statements(subj, pred, obj, context);
					return current;
				}

				@Override
				public void close() {
					if (current != null) {
						current.close();
						current = null;
					}
				}
			};
		}

		@TearDown(Level.Trial)
		public void tearDown() throws IOException {
			try {
				if (inferredDataset != null) {
					inferredDataset.close();
				}
			} finally {
				try {
					if (explicitDataset != null) {
						explicitDataset.close();
					}
				} finally {
					closeRepository();
				}
			}
		}
	}

	/** End-to-end explicit-plus-inferred query smoke test for the optimized retained-composite path. */
	@State(Scope.Benchmark)
	public static class CompositeQueryState extends QueryState {

		private static final int ROOTS = 768;

		@Param({ "explicitAndInferred", "explicitOnly" })
		public String sourceShape;

		@Setup(Level.Trial)
		public void setUp() {
			setProperty(PARALLEL_FLAG, "false");
			setProperty(FACTORIZED_ROWS_FLAG, "true");
			setProperty(NATIVE_BATCH_FLAG, "false");
			setProperty(CHUNK_FLAG, "true");
			setProperty(CHUNK_MERGE_FLAG, "false");
			setProperty(CHUNK_SIP_FLAG, "false");
			openRepository();

			ValueFactory vf = SimpleValueFactory.getInstance();
			IRI rootPredicate = vf.createIRI(EX, "compositeRoot");
			IRI valuePredicate = vf.createIRI(EX, "compositeValue");
			IRI tailPredicate = vf.createIRI(EX, "compositeTail");
			LmdbStore store = (LmdbStore) repository.getSail();
			try (LmdbStoreConnection connection = (LmdbStoreConnection) store.getConnection()) {
				connection.begin();
				for (int i = 0; i < ROOTS; i++) {
					IRI subject = vf.createIRI(EX, "composite/subject/" + i);
					IRI middle = vf.createIRI(EX, "composite/middle/" + i);
					IRI value = vf.createIRI(EX, "composite/value/" + i);
					IRI leaf = vf.createIRI(EX, "composite/leaf/" + i);
					boolean inferred = "explicitAndInferred".equals(sourceShape) && (i & 1) != 0;
					if (!"explicitAndInferred".equals(sourceShape) && !"explicitOnly".equals(sourceShape)) {
						throw new IllegalArgumentException(sourceShape);
					}
					if (inferred) {
						connection.addInferredStatement(subject, rootPredicate, middle);
						connection.addInferredStatement(middle, valuePredicate, value);
						connection.addInferredStatement(value, tailPredicate, leaf);
					} else {
						connection.addStatement(subject, rootPredicate, middle);
						connection.addStatement(middle, valuePredicate, value);
						connection.addStatement(value, tailPredicate, leaf);
					}
				}
				connection.commit();
			}
			query = "SELECT ?subject ?value ?leaf WHERE { "
					+ "?subject <" + EX + "compositeRoot> ?middle . "
					+ "?middle <" + EX + "compositeValue> ?value . "
					+ "?value <" + EX + "compositeTail> ?leaf . }";
			expectedRows = ROOTS;
			includeInferred = true;

			long chunkBefore = LmdbNativeChunkPipeline.ENGAGED.get();
			executeChecked();
			if (LmdbNativeChunkPipeline.ENGAGED.get() <= chunkBefore) {
				throw new IllegalStateException(sourceShape + " did not engage the repeated-open chunk probes");
			}
		}

		@TearDown(Level.Trial)
		public void tearDown() throws IOException {
			closeRepositoryAndRestoreProperties();
		}
	}

	public abstract static class QueryState {

		private File dataDir;
		SailRepository repository;
		String query;
		long expectedRows;
		boolean includeInferred;
		boolean verifyBindingChecksum;
		long expectedBindingChecksum;
		private final Map<String, String> previousProperties = new HashMap<>();

		void openRepository() {
			dataDir = Files.newTemporaryFolder();
			repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		}

		void setProperty(String property, String value) {
			if (!previousProperties.containsKey(property)) {
				previousProperties.put(property, System.getProperty(property));
			}
			System.setProperty(property, value);
		}

		long executeChecked() {
			QuerySummary summary = evaluateSummary();
			if (summary.rows != expectedRows) {
				throw new IllegalStateException("expected " + expectedRows + " rows but got " + summary.rows);
			}
			if (verifyBindingChecksum && summary.bindingChecksum != expectedBindingChecksum) {
				throw new IllegalStateException("expected binding checksum " + expectedBindingChecksum + " but got "
						+ summary.bindingChecksum);
			}
			return verifyBindingChecksum ? summary.bindingChecksum : summary.rows;
		}

		QuerySummary evaluateSummary() {
			long rows = 0L;
			long bindingChecksum = 0L;
			try (SailRepositoryConnection connection = repository.getConnection()) {
				TupleQuery tupleQuery = connection.prepareTupleQuery(query);
				tupleQuery.setIncludeInferred(includeInferred);
				try (TupleQueryResult result = tupleQuery.evaluate()) {
					while (result.hasNext()) {
						BindingSet row = result.next();
						validateRow(row);
						if (verifyBindingChecksum) {
							bindingChecksum += bindingChecksum(row);
						}
						rows++;
					}
				}
			}
			return new QuerySummary(rows, bindingChecksum);
		}

		void validateRow(BindingSet row) {
			// Most variants need only the result cardinality; top-K additionally validates its selected rank.
		}

		long bindingChecksum(BindingSet row) {
			return 0L;
		}

		void closeRepository() throws IOException {
			if (repository != null) {
				repository.shutDown();
			}
			if (dataDir != null) {
				FileUtil.deleteDir(dataDir);
			}
		}

		void closeRepositoryAndRestoreProperties() throws IOException {
			try {
				closeRepository();
			} finally {
				for (Map.Entry<String, String> entry : previousProperties.entrySet()) {
					if (entry.getValue() == null) {
						System.clearProperty(entry.getKey());
					} else {
						System.setProperty(entry.getKey(), entry.getValue());
					}
				}
				previousProperties.clear();
			}
		}
	}

	private static final class QuerySummary {
		final long rows;
		final long bindingChecksum;

		private QuerySummary(long rows, long bindingChecksum) {
			this.rows = rows;
			this.bindingChecksum = bindingChecksum;
		}
	}

	@Benchmark
	public long directHashReplay(HashReplayState state) {
		return state.executeChecked();
	}

	@Benchmark
	public long orderedTopKReplacementChurn(TopKReplacementState state) {
		return state.executeChecked();
	}

	@Benchmark
	public long isolatedTopKPayloadChurn(IsolatedTopKPayloadState state) {
		return state.executeChecked();
	}

	@Benchmark
	public long externalRootChunkSelect(ExternalRootChunkState state) {
		return state.executeChecked();
	}

	@Benchmark
	public long matchedCompositeProbeOpens(CompositeProbeState state) throws IOException {
		return state.executeCheckedProbes();
	}

	@Benchmark
	public long retainedCompositeProbes(CompositeQueryState state) {
		return state.executeChecked();
	}

	private static SailStore backingStore(LmdbStore store) {
		try {
			Method accessor = LmdbStore.class.getDeclaredMethod("getBackingStore");
			accessor.setAccessible(true);
			return (SailStore) accessor.invoke(store);
		} catch (ReflectiveOperationException e) {
			throw new IllegalStateException("Unable to access the LMDB backing SailStore for benchmark setup", e);
		}
	}

	private static NativeLmdbQuerySource requireNativeDataset(SailDataset dataset) {
		if (!(dataset instanceof NativeLmdbQuerySource)) {
			throw new IllegalStateException("LMDB backing dataset is not a native query source: " + dataset.getClass());
		}
		return (NativeLmdbQuerySource) dataset;
	}

	private static long requiredId(NativeLmdbQuerySource source, Value value) {
		long id = source.idOf(value);
		if (id == NativeLmdbQuerySource.UNKNOWN_ID || id == LmdbNativeAggregateCompiler.NULL_CONTEXT_ID) {
			throw new IllegalStateException("Stored benchmark value has no native ID: " + value);
		}
		return id;
	}

	private static long[] copyNativeBindingIds(BindingSet row, String[] names) {
		long[] ids = new long[names.length];
		for (int i = 0; i < names.length; i++) {
			ids[i] = nativeBindingId(row, names[i]);
		}
		return ids;
	}

	private static void assertNativeBindingIds(BindingSet row, String[] names, long[] expected) {
		for (int i = 0; i < names.length; i++) {
			long actual = nativeBindingId(row, names[i]);
			if (actual != expected[i]) {
				throw new IllegalStateException("binding " + names[i] + " has ID " + actual + " instead of "
						+ expected[i]);
			}
		}
	}

	private static long nativeBindingChecksum(BindingSet row, String[] names) {
		long checksum = 0x9E3779B97F4A7C15L;
		for (String name : names) {
			checksum = Long.rotateLeft(checksum ^ nativeBindingId(row, name), 17) * 0xC2B2AE3D27D4EB4FL;
		}
		return checksum;
	}

	private static long nativeBindingChecksum(long first, long second) {
		long checksum = Long.rotateLeft(0x9E3779B97F4A7C15L ^ first, 17) * 0xC2B2AE3D27D4EB4FL;
		return Long.rotateLeft(checksum ^ second, 17) * 0xC2B2AE3D27D4EB4FL;
	}

	private static long nativeBindingId(BindingSet row, String name) {
		if (!(row instanceof NativeProjectedBindingSet)) {
			throw new IllegalStateException("benchmark expected native projected bindings but got " + row.getClass());
		}
		NativeProjectedBindingSet nativeRow = (NativeProjectedBindingSet) row;
		int index = nativeRow.indexOf(name);
		if (index < 0 || !NativeProjectedBindingSet.isBound(nativeRow.ids[index])) {
			throw new IllegalStateException("benchmark result is missing binding " + name);
		}
		return nativeRow.ids[index];
	}

	public static void main(String[] args) throws RunnerException {
		Options options = new OptionsBuilder()
				.include("LmdbNativeSubstrateBenchmark")
				.build();
		new Runner(options).run();
	}
